class Solution {
    public double new21Game(int n, int k, int maxPts) {
        if (k == 0) {
            return 1.0;
        }
        double[] dp = new double[n + 1];
        double sum = 0;
        for (int i = 1; i <= maxPts; i++) {
            sum += 1.0 / maxPts;
        }
        dp[0] = 1.0;
        for (int i = 1; i <= n; i++) {
            dp[i] = sum;
            if (i < k) {
                sum -= dp[i - 1] / maxPts;
            }
        }
        double res = 0;
        for (int i = k; i <= n; i++) {
            res += dp[i];
        }
        return res;
    }
}
